Here's how to handle each scenario with modern MSTest (3.9+/3.10+) attributes:

```csharp
// 1. Windows-only: skip on Linux/macOS
[TestMethod]
[OSCondition(OperatingSystems.Windows)]
public void Registry_ReadsExpectedValue()
{
    var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\MyApp", "Setting", null);
    Assert.IsNotNull(value);
}

// 2. Skip in CI (requires local GPU)
[TestMethod]
[CICondition(ConditionMode.Exclude)]
public void RenderScene_ProducesExpectedOutput()
{
    var result = GpuRenderer.Render(scene);
    Assert.IsNotNull(result);
}

// 3. Flaky external API — retry up to 3 times
[TestMethod]
[Retry(3)]
public async Task GetWeather_ReturnsData()
{
    var weather = await _weatherClient.GetCurrentAsync("Seattle");
    Assert.IsNotNull(weather);
    Assert.IsGreaterThan(0, weather.TemperatureF);
}

// 4. Cleanup temp files even on failure — use [TestCleanup]
[TestClass]
public sealed class FileExportTests
{
    private string _tempFile = string.Empty;

    [TestInitialize]
    public void Setup()
    {
        _tempFile = Path.GetTempFileName();
    }

    [TestMethod]
    public void Export_WritesValidContent()
    {
        var exporter = new DataExporter();
        exporter.Export(_tempFile);

        var content = File.ReadAllText(_tempFile);
        Assert.Contains("header", content);
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Runs even if the test fails
        if (File.Exists(_tempFile))
            File.Delete(_tempFile);
    }
}
```

**Key points:**

| Scenario | Attribute/Pattern | MSTest version |
|---|---|---|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky retry | `[Retry(3)]` | 3.9+ |
| Guaranteed cleanup | `[TestCleanup]` method | All versions |

- `[TestCleanup]` runs after every test **regardless of pass/fail** — it's the right place for file/resource cleanup.
- `[Retry]` should only be used for genuinely flaky external dependencies, not to mask race conditions.
- `[OSCondition]` and `[CICondition]` cause tests to be **skipped** (not failed) on non-matching environments.
